  const NavIcon = ({ icon: Icon, active, onClick, label }: { icon: any, active: boolean, onClick: () => void, label: string }) => (
    <button 
      onClick={onClick}
      className={`p-3 sm:p-4 rounded-2xl transition-all relative group ${active ? 'text-ink' : 'text-muted hover:text-ink hover:bg-white border border-transparent hover:border-gray-100'}`}
      title={label}
    >
      <Icon size={24} strokeWidth={active ? 2.5 : 2} />
      {active && <motion.div layoutId="nav-pill" className="absolute -bottom-1 left-1/2 -translate-x-1/2 h-1 w-6 bg-ink rounded-full" />}
      <span className="absolute -bottom-8 left-1/2 -translate-x-1/2 bg-ink text-white text-[10px] font-bold px-2 py-1 rounded opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none whitespace-nowrap uppercase tracking-widest">
        {label}
      </span>
    </button>
  );

const SidebarItem = ({ icon: Icon, label, active, onClick, badge }: any) => (
  <motion.button 
    whileTap={{ scale: 0.98 }}
    onClick={onClick}
    className={`w-full flex items-center justify-between px-6 py-4 rounded-2xl transition-all duration-300 group relative overflow-hidden ${
      active 
        ? 'bg-accent/5 text-accent' 
        : 'text-muted hover:bg-white border border-transparent hover:border-gray-100 hover:text-ink'
    }`}
  >
    <div className="flex items-center gap-4 relative z-10">
      <Icon size={20} className={`${active ? 'text-accent' : 'text-muted group-hover:text-ink'} transition-colors duration-300`} />
      <span className={`text-[14px] font-bold tracking-tight transition-colors duration-300 ${active ? 'text-accent' : 'text-muted group-hover:text-ink'}`}>{label}</span>
    </div>
    {badge && (
      <span className="bg-accent text-white text-[10px] font-bold px-2 py-0.5 rounded-full relative z-10">
        {badge}
      </span>
    )}
    {active && (
      <motion.div 
        layoutId="sidebar-active"
        className="absolute left-0 top-0 bottom-0 w-1 bg-accent"
      />
    )}
  </motion.button>
);

const WordLayout = ({ 
  title, 
  subtitle, 
  icon: Icon, 
  children, 
  toolbar,
  branding,
  showNotification,
  handlePrint,
  hideOfficialBadge = false,
  hideSaveImage = false,
  hideBranding = false,
  hideIcon = false
}: { 
  title: string, 
  subtitle: string, 
  icon: any, 
  children: React.ReactNode, 
  toolbar?: React.ReactNode,
  branding?: { logo?: string, name?: string },
  showNotification: (msg: string, type?: 'success' | 'error') => void,
  handlePrint: () => void,
  hideOfficialBadge?: boolean,
  hideSaveImage?: boolean,
  hideBranding?: boolean,
  hideIcon?: boolean
}) => {
  const contentRef = useRef<HTMLDivElement>(null);
  const [isExporting, setIsExporting] = useState(false);

  const triggerDownload = (url: string, fileName: string) => {
    // Check if we are in Telegram Mini App
    const isTelegram = (window as any).Telegram?.WebApp?.initData;
    
    if (isTelegram && url.startsWith('data:')) {
      // In Telegram, direct blob/base64 downloads often fail
      // We'll try to show it in a new window or use Telegram's openLink if it's a real URL
      // For images, showing them in a new window allows long-press "Save to Gallery"
      const newWin = window.open();
      if (newWin) {
        newWin.document.write(`<img src="${url}" style="width: 100%; height: auto;" />`);
        newWin.document.title = fileName;
        showNotification('Image opened. Long-press to save to your device.');
      } else {
        showNotification('Please allow popups to save images');
      }
      return;
    }

    const link = document.createElement('a');
    link.href = url;
    link.download = fileName;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleSaveAsImage = async () => {
    if (!contentRef.current) return;
    setIsExporting(true);
    try {
      const dataUrl = await toPng(contentRef.current, {
        cacheBust: true,
        backgroundColor: '#ffffff',
        pixelRatio: 1.5, // Lower for mobile memory
        skipFonts: false,
        style: {
          transform: 'scale(1)',
          transformOrigin: 'top left',
          width: contentRef.current.offsetWidth + 'px',
          height: contentRef.current.offsetHeight + 'px',
        }
      });
      triggerDownload(dataUrl, `${branding?.name?.toLowerCase().replace(/\s+/g, '-') || 'exona'}-${title.toLowerCase().replace(/\s+/g, '-')}-${new Date().getTime()}.png`);
    } catch (err) {
      console.error('Failed to save as image:', err);
      showNotification('Failed to save image. Try the Print option or Screenshot.', 'error');
    } finally {
      setIsExporting(false);
    }
  };

  return (
    <div className="flex flex-col bg-white">
      {/* Ribbon Header */}
      <div className="bg-white border-b border-gray-200 z-20 sticky top-0 no-print">
        <div className="flex items-center justify-between px-4 md:px-6 py-3 border-b border-gray-100">
          <div className="flex items-center gap-3 md:gap-4">
            {!hideIcon && (
              <div className="h-8 w-8 bg-ink rounded-lg flex items-center justify-center text-white shrink-0">
                <Icon size={18} />
              </div>
            )}
            <div className="min-w-0">
              <h2 className="text-sm font-bold text-ink leading-none truncate font-display">{title}</h2>
              <p className="text-[10px] text-muted font-bold uppercase tracking-[0.2em] mt-1 truncate">{subtitle}</p>
            </div>
          </div>
          <div className="flex items-center gap-1 md:gap-2 shrink-0">
            <button 
              onClick={handlePrint}
              className="flex items-center gap-2 px-3 py-1.5 bg-white text-ink border border-gray-100 rounded-lg font-bold text-[10px] uppercase tracking-wider hover:bg-gray-50 transition-all"
            >
              <Printer size={14} />
              Print
            </button>
            {/* {!hideSaveImage && (
              <button 
                onClick={handleSaveAsImage}
                disabled={isExporting}
                className="flex items-center gap-2 px-3 py-1.5 bg-gray-50 text-ink border border-gray-100 rounded-lg font-bold text-[10px] uppercase tracking-wider hover:bg-gray-100 transition-all disabled:opacity-50"
              >
                {isExporting ? (
                  <div className="h-3 w-3 border-2 border-ink/20 border-t-ink rounded-full animate-spin" />
                ) : (
                  <Download size={14} />
                )}
                {isExporting ? 'Exporting...' : 'Save as Image'}
              </button>
            )} */}
          </div>
        </div>
        {/* Toolbar / Ribbon Tabs */}
        <div className="px-4 md:px-6 py-2 flex flex-wrap items-center gap-2 sm:gap-4 bg-white">
          {toolbar}
        </div>
      </div>

      {/* Canvas Area */}
      <div className="p-0 sm:p-4 md:p-8 lg:p-12 flex justify-center bg-gray-50/30">
        <motion.div 
          ref={contentRef}
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          className="w-full md:max-w-[1000px] bg-white min-h-screen md:min-h-[1200px] p-6 sm:p-10 md:p-16 lg:p-20 rounded-none md:rounded-sm border-x-0 md:border-x border-gray-200 relative mb-0 md:mb-20 pb-32 sm:pb-40 print-content"
        >
          {/* Page Header Decor */}
          <div className="absolute top-0 left-0 w-full h-1 bg-ink/5" />
          <div className="flex justify-between items-start mb-20">
            {!hideBranding ? (
              <div className="flex items-center gap-3">
                {branding?.logo ? (
                  <img src={branding.logo} className="h-12 w-12 rounded-2xl object-cover shrink-0" referrerPolicy="no-referrer" crossOrigin="anonymous" />
                ) : (
                  <div className="h-12 w-12 bg-ink text-white rounded-2xl flex items-center justify-center font-black text-xl shrink-0">
                    {branding?.name?.charAt(0) || 'E'}
                  </div>
                )}
                <div>
                  <h1 className="text-xl font-black text-ink tracking-tighter leading-none uppercase">{branding?.name || ''}</h1>
                  {!hideOfficialBadge && (
                    <p className="text-[8px] font-bold text-muted uppercase tracking-[0.4em] mt-1">Institutional Record</p>
                  )}
                </div>
              </div>
            ) : (
              <div className="flex items-center gap-3">
                <div>
                  <h1 className="text-xl font-black text-ink tracking-tighter leading-none uppercase">{branding?.name || ''}</h1>
                </div>
              </div>
            )}
            <div className="text-right">
              <div className="text-[10px] font-bold text-muted uppercase tracking-widest mb-1">Document ID</div>
              <div className="text-sm font-mono font-bold text-ink">#{Math.random().toString(36).substring(2, 8).toUpperCase()}</div>
            </div>
          </div>
          {children}
        </motion.div>
      </div>
    </div>
  );
};

const FeedPost = ({ 
  post, 
  onUserClick, 
  onInstitutionClick,
  onLike, 
  onComment, 
  onMessage, 
  onReshare, 
  onForward, 
  onEdit, 
  onDelete, 
  currentUserId, 
  canManage, 
  canReply = true,
  fallbackLikesState
}: any) => {
  const [showMenu, setShowMenu] = useState(false);
  
  // Resolve likes state: is it a local fallback post or real Firebase post?
  const isFallback = post.id && post.id.startsWith('fallback-');
  const postLikesInfo = (isFallback && fallbackLikesState && fallbackLikesState[post.id]) || {
    likes: post.likes || 0,
    likedBy: post.likedBy || []
  };

  const displayLikes = postLikesInfo.likes;
  const isLiked = postLikesInfo.likedBy?.includes(currentUserId || 'temp-guest-uid');
  const isOwnPost = post.authorUid === currentUserId;

  return (
    <motion.div 
      initial={{ opacity: 0, y: 12 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true }}
      className="bg-white rounded-3xl p-5 mb-5 border border-zinc-150/80 shadow-sm transition-all relative"
    >
      {/* Post Owner / Header Block */}
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center gap-3 min-w-0">
          <button 
            onClick={() => onUserClick?.({ uid: post.authorUid, name: post.authorName, photo: post.authorPhoto })}
            className="shrink-0 relative group"
          >
            {post.authorPhoto ? (
              <img 
                src={post.authorPhoto} 
                className="h-11 w-11 rounded-full object-cover ring-2 ring-zinc-50 border border-zinc-200" 
                referrerPolicy="no-referrer" 
                alt={post.authorName}
              />
            ) : (
              <div className="h-11 w-11 rounded-full bg-zinc-100 border border-zinc-200 flex items-center justify-center text-zinc-700 font-bold text-base">
                {post.authorName?.charAt(0)}
              </div>
            )}
          </button>
          
          <div className="flex flex-col min-w-0">
            <div className="flex items-center gap-1.5 flex-wrap">
              <button 
                onClick={() => onUserClick?.({ uid: post.authorUid, name: post.authorName, photo: post.authorPhoto })}
                className="text-[14.5px] font-black text-zinc-900 hover:text-blue-600 transition-colors tracking-tight text-left leading-normal"
              >
                {post.authorName}
              </button>
              {post.authorRole === 'admin' && <Shield size={12} className="text-blue-600 fill-blue-500/10 shrink-0" />}
              
              {post.schoolId && (
                <button 
                  onClick={() => onInstitutionClick?.(post.schoolId)}
                  className="px-2 py-0.5 rounded-md bg-blue-50 text-[9px] font-extrabold text-blue-600 hover:bg-blue-100 transition-colors uppercase tracking-wider shrink-0"
                >
                  {post.schoolName}
                </button>
              )}
            </div>
            <span className="text-[11px] font-medium text-zinc-400 mt-0.5">
              {formatTime(post.timestamp)}
            </span>
          </div>
        </div>

        {/* Action Dropdown Menu */}
        <div className="relative shrink-0">
          <button 
            onClick={() => setShowMenu(!showMenu)}
            className="h-8 w-8 text-zinc-400 hover:text-zinc-800 hover:bg-zinc-100/60 rounded-full transition-all flex items-center justify-center"
          >
            <MoreHorizontal size={18} />
          </button>
          
          <AnimatePresence>
            {showMenu && (
              <motion.div 
                initial={{ opacity: 0, scale: 0.95, y: -10 }}
                animate={{ opacity: 1, scale: 1, y: 0 }}
                exit={{ opacity: 0, scale: 0.95, y: -10 }}
                className="absolute right-0 mt-2 w-48 bg-white border border-zinc-100 rounded-2xl py-2 z-30 shadow-xl"
              >
                {(isOwnPost || canManage) && (
                  <>
                    <button 
                      onClick={() => { onEdit?.(post); setShowMenu(false); }}
                      className="w-full px-4 py-2.5 text-left text-[11px] font-bold text-zinc-700 hover:bg-zinc-50 flex items-center gap-3 transition-colors uppercase tracking-widest"
                    >
                      <Edit2 size={13} className="text-zinc-400" /> Edit Post
                    </button>
                    <button 
                      onClick={() => { onDelete?.(post); setShowMenu(false); }}
                      className="w-full px-4 py-2.5 text-left text-[11px] font-bold text-red-600 hover:bg-red-50 flex items-center gap-3 transition-colors uppercase tracking-widest"
                    >
                      <Trash2 size={13} /> Delete Post
                    </button>
                    <div className="h-px bg-zinc-100 my-1.5" />
                  </>
                )}
                <button 
                  onClick={() => { onReshare?.(post); setShowMenu(false); }}
                  className="w-full px-4 py-2.5 text-left text-[11px] font-bold text-zinc-700 hover:bg-zinc-50 flex items-center gap-3 transition-colors uppercase tracking-widest"
                >
                  <Share2 size={13} className="text-zinc-400" /> Share Post
                </button>
              </motion.div>
            )}
          </AnimatePresence>
        </div>
      </div>

      {/* Post Text Description Message */}
      <h3 className="text-[15.5px] leading-relaxed text-zinc-900 whitespace-pre-wrap mb-4 font-semibold tracking-tight px-0.5">
        {post.content}
      </h3>

      {/* Reshared Post Block */}
      {post.resharedFrom && (
        <div className="mb-4 p-4 bg-zinc-50/70 border border-zinc-150 rounded-2xl border-l-4 border-blue-500/30">
          <div className="flex items-center gap-2 mb-2">
            <Repeat size={13} className="text-blue-500" />
            <p className="text-[10px] font-bold text-blue-600 uppercase tracking-widest">{post.resharedFrom.authorName}</p>
          </div>
          <p className="text-[13px] text-zinc-500 leading-relaxed font-semibold">{post.resharedFrom.content}</p>
        </div>
      )}

      {/* Beautiful Rounded Attachment Graphic (Main Image) */}
      {(post.mediaUrl || (post.mediaUrls && post.mediaUrls.length > 0)) && (
        <div className={`mb-4 rounded-2xl overflow-hidden border border-zinc-150 bg-zinc-50 group/media ${post.mediaUrls && post.mediaUrls.length > 1 ? 'grid grid-cols-2 gap-1' : ''}`}>
          {post.mediaUrls && post.mediaUrls.length > 0 ? (
            post.mediaUrls.map((url: string, idx: number) => (
              <div key={idx} className={post.mediaUrls!.length === 1 ? '' : 'aspect-square relative overflow-hidden'}>
                {post.mediaType === 'image' ? (
                  <img 
                    src={url} 
                    className="w-full h-full object-cover group-hover/media:scale-[1.03] transition-transform duration-700" 
                    referrerPolicy="no-referrer" 
                    alt="Post Attachment"
                  />
                ) : (
                  <video src={url} controls className="w-full h-full object-contain bg-black" />
                )}
              </div>
            ))
          ) : (
            <div className="relative overflow-hidden">
              {post.mediaType === 'image' ? (
                <img 
                  src={post.mediaUrl} 
                  className="w-full h-auto max-h-[460px] object-cover group-hover/media:scale-[1.03] transition-transform duration-700" 
                  referrerPolicy="no-referrer" 
                  alt="Post Attachment"
                />
              ) : (
                <video src={post.mediaUrl} controls className="w-full h-full object-contain bg-black" />
              )}
            </div>
          )}
        </div>
      )}

      {/* Premium Social Stacked Reactions Count Row */}
      <div className="flex items-center justify-between px-1.5 py-2.5 border-b border-zinc-100 text-xs text-zinc-500">
        <div className="flex items-center gap-1.5">
          <div className="flex -space-x-1 items-center select-none">
            {/* Standard stacked reactions */}
            <div className="h-5 w-5 rounded-full bg-blue-500 flex items-center justify-center text-white ring-2 ring-white">
              <ThumbsUp size={10} className="fill-white text-white" />
            </div>
            <div className="h-5 w-5 rounded-full bg-red-500 flex items-center justify-center text-white ring-2 ring-white">
              <Heart size={10} className="fill-white text-white" />
            </div>
            <div className="h-5 w-5 rounded-full bg-teal-500 flex items-center justify-center text-white ring-2 ring-white">
              <Sparkles size={10} className="text-white" />
            </div>
          </div>
          <span className="ml-1 text-[13px] font-bold text-zinc-600 leading-none">
            {displayLikes > 0 ? displayLikes : displayLikes === 0 ? 0 : 128}
          </span>
        </div>
        
        <button 
          onClick={() => canReply && onComment?.(post)}
          className="text-[13px] font-bold text-zinc-500 hover:text-blue-600 transition-colors hover:underline"
        >
          {post.commentsCount > 0 ? `${post.commentsCount} Comments` : isFallback ? `${post.commentsCount || 45} Comments` : 'Add Comment'}
        </button>
      </div>

      {/* Interactive Activity Control Bar */}
      <div className="flex items-center justify-around pt-3">
        <button 
          onClick={() => onLike?.(post.id, postLikesInfo.likedBy || [])}
          className={`flex items-center justify-center gap-2 py-2 px-6 rounded-xl transition-all text-[13px] font-bold outline-none group hover:bg-zinc-50 active:scale-95 ${
            isLiked ? 'text-blue-600' : 'text-zinc-500 hover:text-zinc-800'
          }`}
        >
          <ThumbsUp size={17} className={isLiked ? 'fill-blue-600 text-blue-600' : 'text-zinc-400 group-hover:text-zinc-600'} />
          <span>Like</span>
        </button>

        <button 
          onClick={() => canReply && onComment?.(post)}
          className="flex items-center justify-center gap-2 py-2 px-6 rounded-xl transition-all text-[13px] font-bold text-zinc-500 hover:text-zinc-800 hover:bg-zinc-50 active:scale-95 group"
        >
          <MessageCircle size={17} className="text-zinc-400 group-hover:text-zinc-600" />
          <span>Comment</span>
        </button>

        <button 
          onClick={() => onReshare?.(post)}
          className="flex items-center justify-center gap-2 py-2 px-6 rounded-xl transition-all text-[13px] font-bold text-zinc-500 hover:text-zinc-800 hover:bg-zinc-50 active:scale-95 group"
        >
          <Share2 size={17} className="text-zinc-400 group-hover:text-zinc-600" />
          <span>Share</span>
        </button>
      </div>

      {/* Secret Message Button Hidden from Public Feed as Requested but available for Direct Secure Chats */}
      {!isOwnPost && onMessage && (
        <button 
          onClick={() => onMessage?.(post)}
          className="absolute bottom-4 right-4 p-2 bg-zinc-50 hover:bg-zinc-100 rounded-full text-zinc-400 hover:text-zinc-700 transition-all border border-zinc-100 hidden"
          title="Direct Message"
        >
          <Smartphone size={14} />
        </button>
      )}
    </motion.div>
  );
};

