  const [serverReady, setServerReady] = useState(false);
  const [renderedView, setRenderedView] = useState<typeof view>('splash');

  // Instant view loading flag calculated on the fly for immediate feedback on the same tick as clicks
  const isViewLoading = view !== renderedView && view !== 'splash' && renderedView !== 'splash';

  // Unified visual view loader to fetch & process data gracefully like Facebook
  useEffect(() => {
    if (view === renderedView) return;

    // Fast-track initial transitions so cold boots show instant menus
    if (renderedView === 'splash') {
      setRenderedView(view);
      return;
    }

    const timer = setTimeout(() => {
      setRenderedView(view);
    }, 850); // 850ms elegant Facebook-style connection delay to ensure they see the loader clearly

    return () => clearTimeout(timer);
  }, [view, renderedView]);

  useEffect(() => {
    let checkInterval: any;
    const checkServer = () => {
      fetch(`/api/health?cb=${Date.now()}`)
        .then(res => res.json())
        .then(data => {
          if (data.status === 'ok') {
            console.log("Presidential Server is READY");
            setServerReady(true);
            clearInterval(checkInterval);
          }
        })
        .catch(() => {
          console.warn("Waiting for Presidential Server...");
        });
    };
    checkInterval = setInterval(checkServer, 5000);
    checkServer();
    return () => clearInterval(checkInterval);
  }, []);

  const fetchBroadcastHistory = useCallback(() => {
    if (!serverReady) return;
    fetch(`/api/admin/broadcasts?cb=${Date.now()}`)
      .then(res => {
        if (!res.ok) {
          return res.text().then(text => {
            throw new Error(`HTTP ${res.status}: ${text}`);
          });
        }
        return res.json();
      })
      .then(data => {
        if (data.success) setBroadcastHistory(data.broadcasts);
      })
      .catch(err => {
        if (err.message === 'Failed to fetch' || err.name === 'TypeError') {
          console.warn('[Presidential Broadcasts] Network transition, retrying shortly...', err.message);
          // Silent retry in background
          setTimeout(fetchBroadcastHistory, 15000);
        } else {
          console.warn('[Presidential Broadcasts] Non-fatal load issue:', err.message || err);
        }
      });
  }, [serverReady]);

  const startY = useRef(0);
  const scrollContainerRef = useRef<HTMLDivElement>(null);

  const handleTouchStart = (e: React.TouchEvent) => {
    if (scrollContainerRef.current?.scrollTop === 0) {
      startY.current = e.touches[0].pageY;
    } else {
      startY.current = 0;
    }
  };

  const handleTouchMove = (e: React.TouchEvent) => {
    if (startY.current === 0 || refreshing) return;
    const currentY = e.touches[0].pageY;
    const diff = currentY - startY.current;
    if (diff > 0 && scrollContainerRef.current && scrollContainerRef.current.scrollTop <= 0) {
      setPullDistance(diff);
      // Prevent browser's native pull-to-refresh
      if (e.cancelable) e.preventDefault();
    }
  };

  const handleTouchEnd = () => {
    if (pullDistance > 80 && !refreshing) {
      setRefreshing(true);
      // Clear posts to force a visual refresh and handle the case where postsLimit is already 10
      setPosts([]);
      setPostsLimit(10);
      setHasMorePosts(true);
      
      // Also refresh broadcast history and other stats
      fetchBroadcastHistory();
      
      setTimeout(() => {
        setRefreshing(false);
        setPullDistance(0);
        showNotification('Feed Updated', 'success');
      }, 1200);
    } else {
      setPullDistance(0);
    }
    startY.current = 0;
  };

  useEffect(() => {
    if (!serverReady) return;
    const fetchStats = () => {
      // Use absolute path and cache buster to bypass potential proxy issues
      fetch(`/api/admin/stats?cb=${Date.now()}`)
        .then(res => {
          if (!res.ok) {
            return res.text().then(text => {
              throw new Error(`HTTP ${res.status}: ${text}`);
            });
          }
          return res.json();
        })
        .then(data => {
          if (data.success) {
            setCommunitySize(data.communitySize);
          }
        })
        .catch(err => {
          if (err.message === 'Failed to fetch' || err.name === 'TypeError') {
            console.warn('[Presidential Stats] Network transition, retrying shortly...', err.message);
            // Silently retry stats in 15s if it's a network/proxy issue
            setTimeout(fetchStats, 15000);
          } else {
            console.warn('[Presidential Stats] Non-fatal load issue:', err.message || err);
          }
        });
    };
    
    // Add a small delay for the initial fetch to ensure server is fully settled
    const timeout = setTimeout(fetchStats, 1000);
    fetchBroadcastHistory();
    return () => clearTimeout(timeout);
  }, [fetchBroadcastHistory, serverReady]);
