  const playNotificationSound = (type: 'message' | 'call' = 'message') => {
    // Handle Telegram Haptic Feedback
    if (window.Telegram?.WebApp?.HapticFeedback) {
      if (type === 'call') {
        window.Telegram.WebApp.HapticFeedback.notificationOccurred('warning');
      } else {
        window.Telegram.WebApp.HapticFeedback.notificationOccurred('success');
      }
    }

    try {
      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
      
      const playPattern = (freq: number, duration: number, startTime: number) => {
        const oscillator = audioCtx.createOscillator();
        const gainNode = audioCtx.createGain();
        oscillator.connect(gainNode);
        gainNode.connect(audioCtx.destination);
        
        oscillator.type = type === 'call' ? 'sine' : 'triangle';
        oscillator.frequency.setValueAtTime(freq, startTime);
        
        gainNode.gain.setValueAtTime(0.3, startTime);
        gainNode.gain.exponentialRampToValueAtTime(0.01, startTime + duration);
        
        oscillator.start(startTime);
        oscillator.stop(startTime + duration);
      };

      if (type === 'call') {
        // Insistent triple-tone sequence like a pager or urgent call
        playPattern(440, 0.5, audioCtx.currentTime);
        playPattern(660, 0.5, audioCtx.currentTime + 0.3);
        playPattern(880, 0.8, audioCtx.currentTime + 0.6);
        
        // Vibration pattern: [Wait, Pulse, Wait, Pulse...]
        if ('vibrate' in navigator) {
          navigator.vibrate([200, 100, 200, 100, 500]);
        }
      } else {
        // Modern tech chime
        playPattern(880, 0.3, audioCtx.currentTime);
        playPattern(1046.5, 0.4, audioCtx.currentTime + 0.1);
        
        if ('vibrate' in navigator) {
          navigator.vibrate(100);
        }
      }
    } catch (e) {
      console.warn('Audio/Vibration feedback blocked:', e);
    }
  };

  const triggerSystemNotification = (title: string, body: string, category: string = 'system') => {
    const appName = 'Exona Protocol';
    const fullTitle = `${appName}: ${title}`;

    // If in Telegram, we can also use their native UI for critical alerts
    if (window.Telegram?.WebApp && (category === 'treasury' || category === 'system')) {
      if (window.Telegram.WebApp.isVersionAtLeast?.('6.2')) {
        window.Telegram.WebApp.showConfirm(`${fullTitle}\n\n${body}`);
      }
    }

    if ('Notification' in window) {
      if (Notification.permission === 'granted') {
        // Try to use the service worker for better background reliability
        navigator.serviceWorker.ready.then(registration => {
          (registration as any).showNotification(fullTitle, {
            body,
            icon: '/favicon.ico',
            badge: '/favicon.ico',
            tag: category,
            vibrate: category === 'social' ? [200, 100, 200] : [100],
            requireInteraction: category === 'social' || category === 'treasury'
          });
        }).catch(() => {
          // Fallback to standard notification if SW is not ready
          new Notification(fullTitle, {
            body,
            icon: '/favicon.ico',
            tag: category
          });
        });
      }
    }
    // Always play sound/haptic regardless of browser permissions if app is open
    playNotificationSound(category === 'social' ? 'call' : 'message');
  };

  const requestNotificationPermission = async () => {
    if (!('Notification' in window)) {
      showNotification('System alerts not supported on this browser', 'error');
      return;
    }
    
    const isIframe = window.self !== window.top;

    if (Notification.permission === 'denied') {
      showNotification(
        isIframe 
          ? 'Telegram security is blocking alerts. Open in New Tab to enable.' 
          : 'Alerts are blocked in browser settings. Reset permissions to continue.', 
        'error'
      );
      return;
    }

    try {
      // Use the older callback syntax for better compatibility with some mobile browsers
      Notification.requestPermission((permission) => {
        setNotificationPermission(permission);
        if (permission === 'granted') {
          showNotification('System-level alerts active', 'success');
          triggerSystemNotification('Security Protocol Engaged', 'Outside-app notifications are now synchronized.', 'system');
        } else {
          showNotification('Permission was not granted', 'error');
        }
      });
    } catch (err) {
      // Fallback for newer promise-based API
      const permission = await Notification.requestPermission();
      setNotificationPermission(permission);
      if (permission === 'granted') {
        showNotification('System-level alerts active', 'success');
        triggerSystemNotification('Security Protocol Engaged', 'Outside-app notifications are now synchronized.', 'system');
      }
    }
  };

  const [starsNeeded, setStarsNeeded] = useState(0);
