  const [isRequestingKey, setIsRequestingKey] = useState(false);
  const [activeKeyRequest, setActiveKeyRequest] = useState<any | null>(null);
  const [verifiedPortalAccess, setVerifiedPortalAccess] = useState<string[]>([]);
  const [pendingKeyRequests, setPendingKeyRequests] = useState<any[]>([]);
  const [schools, setSchools] = useState<School[]>([]);

  function canManageInstitution(school: School | Place | null) {
    if (!user) return false;
    if (userDoc?.role === 'admin') return true;
    if (!school) return false;
    
    // Always check main state for latest data
    const latestSchool = schools.find(s => s.id === school.id) || 
                         places.find(p => p.id === school.id) || 
                         school;

    return latestSchool.creatorUid === user.uid || 
           (latestSchool.administrativeViewers && latestSchool.administrativeViewers.includes(user.uid));
  }

  function canAccessInstitutionData(school: School | Place | null) {
    if (!user || !school) return false;
    if (userDoc?.role === 'admin') return true;

    const latest = schools.find(s => s.id === school.id) || 
                   places.find(p => p.id === school.id) || 
                   school;
    
    // Access allowed for: Creator, Administrative Viewers (Auditors), and Approved Followers (Members)
    return latest.creatorUid === user.uid || 
           (latest.administrativeViewers && latest.administrativeViewers.includes(user.uid)) ||
           (latest.followers && latest.followers.includes(user.uid));
  }

  function handleNavigateToData(targetView: string, schoolOverride?: School | Place | null) {
    const baseSchool = schoolOverride || selectedSchool;
    if (!baseSchool) {
      showNotification('Please select an institution first', 'error');
      setView('schools');
      setSidebarOpen(false);
      return;
    }

    // Always use the latest data from the collections to ensure current permissions are used
    const school = schools.find(s => s.id === baseSchool.id) || 
                   places.find(p => p.id === baseSchool.id) || 
                   baseSchool;

    // Direct guard for non-administrative members trying to open Records or Attendance
    if (targetView === 'records' || targetView === 'attendance') {
      const isMgmt = canManageInstitution(school) || userDoc?.role === 'admin';
      if (!isMgmt) {
        const hasPass = institutionSubscriptions[`${school.id}_${targetView}`]?.expiresAt > Date.now();
        if (!hasPass) {
          setInstSubscriptionSelector({
            schoolId: school.id,
            schoolName: school.name,
            type: targetView as 'records' | 'attendance',
            targetView: targetView
          });
          return;
        }
      }
    }

    if (canAccessInstitutionData(school)) {
      setSelectedSchool(school); // Sync it just in case
      setView(targetView as any);
      setSidebarOpen(false);
    } else {
      showNotification('Access denied. You must be an approved member.', 'error');
    }
  }

  function canUserReply(post: Post, school: any) {
    if (!user) return false;
    if (canManageInstitution(school) || userDoc?.role === 'admin') return true;
    const permission = school?.replyPermission || 'everyone';
    if (permission === 'everyone') return true;
    if (permission === 'followers') return school?.followers?.includes(user.uid);
    return false;
  }
  const [selectedSchool, setSelectedSchool] = useState<School | null>(null);

  useEffect(() => {
    if (selectedSchool) {
      const updated = schools.find(s => s.id === selectedSchool.id) || places.find(p => p.id === selectedSchool.id);
      if (updated) {
        const hasChanged = 
          updated.name !== selectedSchool.name || 
          updated.photoUrl !== selectedSchool.photoUrl || 
          (updated.followers || []).length !== (selectedSchool.followers || []).length ||
          (updated.administrativeViewers || []).length !== (selectedSchool.administrativeViewers || []).length;
        if (hasChanged) {
          setSelectedSchool(updated as any);
        }
      }
    }
  }, [schools, places, selectedSchool?.id]);

  const managedFollowersTracker = useMemo(() => {
    return [...schools, ...places]
      .filter(inst => inst.creatorUid === user?.uid || inst.administrativeViewers?.includes(user?.uid || ''))
      .map(inst => `${inst.id}:${(inst.followers || []).join(',')}`)
      .join('|');
  }, [schools, places, user?.uid]);

  const managedIdsTracker = useMemo(() => {
    return [
      ...schools.filter(s => s.creatorUid === user?.uid || s.administrativeViewers?.includes(user?.uid || '')).map(s => s.id),
      ...places.filter(p => p.creatorUid === user?.uid || p.administrativeViewers?.includes(user?.uid || '')).map(p => p.id)
    ].join(',');
  }, [schools, places, user?.uid]);

  const selectedLatestSchoolTracker = useMemo(() => {
    if (!selectedSchool) return '';
    const found = schools.find(s => s.id === selectedSchool.id) || 
                  places.find(p => p.id === selectedSchool.id) || 
                  selectedSchool;
    const canAccessAdmin = found.creatorUid === user?.uid || 
                           userDoc?.role === 'admin' || 
                           (found.administrativeViewers || []).includes(user?.uid || '');
    const canAccessMemberData = canAccessAdmin || (found.followers || []).includes(user?.uid || '');
    return `${found.id}:${canAccessAdmin}:${canAccessMemberData}`;
  }, [selectedSchool?.id, schools, places, user?.uid, userDoc?.role]);

  useEffect(() => {
    if (selectedClassroom) {
      const updated = classrooms.find(c => c.id === selectedClassroom.id);
      if (updated && JSON.stringify(updated) !== JSON.stringify(selectedClassroom)) {
        setSelectedClassroom(updated);
      }
    }
  }, [classrooms, selectedClassroom]);

  useEffect(() => {
    if (selectedClassroom) {
      setEditClassroomName(selectedClassroom.name || '');
      setEditClassroomSubject(selectedClassroom.subject || '');
      setEditClassroomTeacher(selectedClassroom.teacher || '');
      setEditClassroomSchedule(selectedClassroom.schedule || '');
      setEditClassroomDesc(selectedClassroom.description || '');
      setEditClassroomCapacity(selectedClassroom.capacity || 30);
      setEditClassroomPhotoUrl(selectedClassroom.photoUrl || '');

      // Determine if student to default to tasks tab automatically
      const isManager = canManageInstitution(selectedSchool);
      const isClassStaff = isManager || 
                           selectedClassroom.createdByUid === user?.uid || 
                           (selectedClassroom.coAdmins || []).includes(user?.uid || '');
      if (!isClassStaff) {
        setClassroomActiveTab('tasks');
      } else {
        setClassroomActiveTab('stream');
      }

      // Load lesson check-offs
      try {
        const stored = localStorage.getItem(`completed_lessons_${selectedClassroom.id}`);
        if (stored) {
          setCompletedLessonIds(JSON.parse(stored));
        } else {
          setCompletedLessonIds([]);
        }
      } catch (e) {
        setCompletedLessonIds([]);
      }
    } else {
      setEditClassroomName('');
      setEditClassroomSubject('');
      setEditClassroomTeacher('');
      setEditClassroomSchedule('');
      setEditClassroomDesc('');
      setEditClassroomCapacity(30);
      setEditClassroomPhotoUrl('');
      setCompletedLessonIds([]);
    }
  }, [selectedClassroom, selectedSchool, user?.uid]);

  const handleClassroomLinkNavigation = async (classId: string) => {
    try {
      const classDoc = await getDoc(doc(db, 'classrooms', classId));
      if (!classDoc.exists()) {
        showNotification('Classroom not found.', 'error');
        return;
      }
      const classData = { id: classDoc.id, ...classDoc.data() } as Classroom;
      
      const schoolId = classData.schoolId;
      let school = schools.find(s => s.id === schoolId) || places.find(p => p.id === schoolId);
      
      if (!school) {
        const schoolDoc = await getDoc(doc(db, 'schools', schoolId));
        if (schoolDoc.exists()) {
          school = { id: schoolDoc.id, ...schoolDoc.data() } as any;
        } else {
          const placeDoc = await getDoc(doc(db, 'places', schoolId));
          if (placeDoc.exists()) {
            school = { id: placeDoc.id, ...placeDoc.data() } as any;
          }
        }
      }
      
      if (!school) {
        showNotification('Associated Institution check failed.', 'error');
        return;
      }
      
      setSelectedSchool(school as any);
      setView('classroom');
      
      // Auto-join user if not enrolled, not creator, not manager
      const isEnrolled = classData.students?.includes(user?.uid || '');
      const isTeacher = classData.createdByUid === user?.uid;
      const isManager = school.creatorUid === user?.uid || (school.administrativeViewers && school.administrativeViewers.includes(user?.uid));
      
      if (!isEnrolled && !isTeacher && !isManager && user) {
        await updateDoc(doc(db, 'classrooms', classId), {
          students: arrayUnion(user.uid)
        });
      }
      
      await handleEnterClassroom(classData);
      showNotification(`Redirected to ${classData.name}!`, 'success');
    } catch (err) {
      console.error('Error navigating to classroom:', err);
      showNotification('Failed to open classroom link.', 'error');
    }
  };

  useEffect(() => {
    if (!user) return;
    const urlParams = new URLSearchParams(window.location.search);
    const classId = urlParams.get('classId');
    if (classId) {
      const newParams = new URLSearchParams(window.location.search);
      newParams.delete('classId');
      const searchStr = newParams.toString();
      const newUrl = window.location.pathname + (searchStr ? '?' + searchStr : '');
      window.history.replaceState({}, '', newUrl);
      
      handleClassroomLinkNavigation(classId);
    }
  }, [user]);

  useEffect(() => {
    if (!user?.uid || isQuotaExceeded) return;
    // Listen for calls where user is caller or receiver
    const qCalls = query(
      collection(db, 'calls'),
      where('participants', 'array-contains', user.uid),
      where('status', 'in', ['ringing', 'active']),
      orderBy('timestamp', 'desc'),
      limit(1)
    );

    const unsubscribe = onSnapshot(qCalls, (snapshot) => {
      snapshot.docs.forEach(doc => {
        const data = doc.data();
        if (data.receiverUid === user.uid && data.status === 'ringing') {
          setIncomingCall({ id: doc.id, ...data });
        } else if (data.callerUid === user.uid && data.status === 'ringing') {
          setOutgoingCall({ id: doc.id, ...data });
        } else if ((data.callerUid === user.uid || data.receiverUid === user.uid) && data.status === 'active') {
          // If active, keep track
          if (data.callerUid === user.uid) setOutgoingCall({ id: doc.id, ...data });
          else setIncomingCall({ id: doc.id, ...data });
        }
      });

      // Clear if no active/ringing calls in results for this user
      const relevantCall = snapshot.docs.find(doc => {
        const d = doc.data();
        return (d.callerUid === user.uid || d.receiverUid === user.uid) && (d.status === 'ringing' || d.status === 'active');
      });
      if (!relevantCall) {
        setIncomingCall(null);
        setOutgoingCall(null);
        if (activeCallStream) {
          activeCallStream.getTracks().forEach(t => t.stop());
          setActiveCallStream(null);
        }
      }
    }, (error) => {
      handleFirestoreError(error, OperationType.GET, 'calls');
    });

    return unsubscribe;
  }, [user?.uid, isQuotaExceeded]);

  useEffect(() => {
    if (userDoc?.role !== 'admin' || isQuotaExceeded || view !== 'admin') return;
    
    const q = query(collection(db, 'keyRequests'), where('status', '==', 'pending'), orderBy('timestamp', 'desc'), limit(50));
    const unsubscribe = onSnapshot(q, (snapshot) => {
      setPendingKeyRequests(snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() })));
    }, (error) => {
      handleFirestoreError(error, OperationType.GET, 'keyRequests');
    });
    return unsubscribe;
  }, [userDoc?.role, isQuotaExceeded, view]);

  useEffect(() => {
    if (!user?.uid || isQuotaExceeded || view !== 'workspace') return;
    
    // Listen for ALL key requests made by current user, globally
    const q = query(
      collection(db, 'keyRequests'), 
      where('requesterUid', '==', user.uid),
      orderBy('timestamp', 'desc'),
      limit(20)
    );
    
    const unsubscribe = onSnapshot(q, (snapshot) => {
      if (!snapshot.empty) {
        // If we have a selected school, prefer its request, otherwise use most recent
        const currentReq = selectedSchool 
          ? snapshot.docs.find(d => d.data().institutionId === selectedSchool.id)
          : snapshot.docs[0];
          
        setActiveKeyRequest(currentReq ? currentReq.data() : null);
      } else {
        setActiveKeyRequest(null);
      }
    }, (error) => {
      // Don't log full detailed error for 403s on keyRequests as they might be pre-auth
      console.warn('Key requests listener inhibited:', error);
    });
    return unsubscribe;
  }, [user?.uid, selectedSchool?.id, isQuotaExceeded, view]);

  useEffect(() => {
    if (!selectedSchool) return;
    const updated = schools.find(s => s.id === selectedSchool.id) || places.find(p => p.id === selectedSchool.id);
    if (updated && JSON.stringify(updated) !== JSON.stringify(selectedSchool)) {
      setSelectedSchool(updated);
    }
  }, [schools, places, selectedSchool]);

