  const handleMergePdfs = async () => {
    if (uploadedPdfFiles.length < 2) {
      showNotification('Please upload at least 2 PDF files to merge', 'error');
      return;
    }

    setIsProcessingPdf(true);
    try {
      const mergedPdf = await PDFDocument.create();
      
      for (const file of uploadedPdfFiles) {
        const arrayBuffer = await file.arrayBuffer();
        const pdf = await PDFDocument.load(arrayBuffer);
        const copiedPages = await mergedPdf.copyPages(pdf, pdf.getPageIndices());
        copiedPages.forEach((page) => mergedPdf.addPage(page));
      }

      const mergedPdfBytes = await mergedPdf.save();
      const blob = new Blob([mergedPdfBytes], { type: 'application/pdf' });
      const url = URL.createObjectURL(blob);
      
      const link = document.createElement('a');
      link.href = url;
      link.download = `merged_${Date.now()}.pdf`;
      link.click();
      
      showNotification('PDFs merged successfully', 'success');
      setUploadedPdfFiles([]);
      setActivePdfTool(null);
    } catch (error) {
      console.error('Merge PDF Error:', error);
      showNotification('Failed to merge PDFs', 'error');
    } finally {
      setIsProcessingPdf(false);
    }
  };

  const handleDebitExonStars = async (amount: number, description: string) => {
    if (!user) return false;
    try {
      const walletRef = doc(db, 'wallets', user.uid);
      const historyRef = doc(collection(db, `wallets/${user.uid}/history`));

      const success = await runTransaction(db, async (transaction) => {
        const walletDoc = await transaction.get(walletRef);
        if (!walletDoc.exists()) return { success: false, currentBalance: 0 };
        
        const data = walletDoc.data();
        const currentBalance = data.balance || 0;

        if (currentBalance < amount) {
          return { success: false, currentBalance };
        }

        transaction.update(walletRef, {
          balance: currentBalance - amount,
          last_transaction: serverTimestamp()
        });

        transaction.set(historyRef, {
          amount: amount,
          type: 'debit',
          currency: 'stars',
          description,
          timestamp: serverTimestamp()
        });

        return { success: true };
      });

      if (!success.success) {
        setStarsNeeded(amount - (success.currentBalance || 0));
        setShowInsufficientStarsAlert(true);
        return false;
      }
      
      showNotification(`Spent ${amount} Exon Stars`, 'success');
      return true;
    } catch (error) {
      handleFirestoreError(error, OperationType.WRITE, `wallets/${user.uid}`);
      return false;
    }
  };

