  const handlePurchaseInstSubscription = async (
    schoolId: string, 
    type: 'records' | 'attendance', 
    planId: '4h' | '24h' | 'weekly' | 'monthly'
  ) => {
    if (!user?.uid) {
      showNotification("Please log in first to purchase subscriptions", "error");
      return;
    }
    
    // Find the cost
    const plan = INST_VIEW_PLANS.find(p => p.id === planId);
    if (!plan) return;

    const school = schools.find(s => s.id === schoolId) || places.find(p => p.id === schoolId);
    const schoolName = school ? school.name : 'Institution';

    setIsPurchasingInstSub(true);
    try {
      const success = await handleDebitExcoin(
        plan.cost, 
        `Subscription Pass: ${plan.name} for Space: ${schoolName}`
      );
      if (success) {
        const docId = `${user.uid}_${schoolId}_${type}`;
        const purchasedAt = new Date();
        const expiresAt = new Date(Date.now() + plan.durationMs);

        await setDoc(doc(db, 'broadcast_subscriptions', docId), {
          userId: user.uid,
          streamId: schoolId,
          type,
          plan: planId,
          cost: plan.cost,
          purchasedAt,
          expiresAt,
          streamTitle: schoolName
        });

        // Show successful purchase animation state
        setInstPurchaseSuccessMsg(`Successfully unlocked ${type === 'records' ? 'Member Record' : 'Attendance/Participation'} pass! Duration: ${plan.id === '4h' ? '4 hours' : plan.id === '24h' ? '24 hours' : plan.id === 'weekly' ? '7 days' : '30 days'}.`);
        showNotification(`${type === 'records' ? 'Member Record' : 'Attendance'} Access Unlocked!`, 'success');

        setTimeout(() => {
          setInstPurchaseSuccessMsg('');
          setInstSubscriptionSelector(null);
          setView(type as any);
        }, 2200);
      }
    } catch (err) {
      console.error("Purchase failed:", err);
      showNotification("Purchase transaction error. Please try again.", "error");
    } finally {
      setIsPurchasingInstSub(false);
    }
  };

  const handleEnterClassroom = async (c: Classroom) => {
    if (isEnteringClassroomRef.current) {
      console.log('Classroom entry in progress. Double-click prevention active.');
      return;
    }
    if (!user) {
      showNotification('You must be logged in to access classrooms.', 'error');
      return;
    }
    const isOwner = c.createdByUid === user.uid;
    if (isOwner) {
      setSelectedClassroom(c);
      setClassroomActiveTab('stream');
      return;
    }
    
    const paidSessions = c.paidSessions || {};
    const subscriptionTimestamp = paidSessions[user.uid];
    const now = Date.now();
    const fourHoursInMs = 4 * 60 * 60 * 1000;
    const isSubscriptionActive = subscriptionTimestamp && (now - subscriptionTimestamp < fourHoursInMs);
    
    if (isSubscriptionActive) {
      const remainingMs = fourHoursInMs - (now - subscriptionTimestamp);
      const remainingMins = Math.ceil(remainingMs / (60 * 1000));
      const hours = Math.floor(remainingMins / 60);
      const mins = remainingMins % 60;
      const timeStr = hours > 0 ? `${hours}h ${mins}m` : `${mins}m`;
      showNotification(`Your 4-hour access subscription is active. Time remaining: ${timeStr}`, 'info');
      setSelectedClassroom(c);
      setClassroomActiveTab('stream');
      return;
    }
    
    const hasPriorSession = !!subscriptionTimestamp;
    const kind = selectedSchool?.type === 'place' ? 'hub' : 'classroom';
    const kindTitle = selectedSchool?.type === 'place' ? 'Exona Hub' : 'Exona Classroom';
    const feeToPay = c.entryFee || 10;
    const ownerShare = feeToPay / 2;
    const burnShare = feeToPay / 2;

    const confirmMessage = hasPriorSession
      ? `Your previous 4-hour subscription to "${c.name}" has expired.\n\nDo you want to pay another ${feeToPay} Excoins to renew your subscription for another 4 hours?`
      : `Access to "${c.name}" ${kind} requires a ${feeToPay} Excoin access fee.\n\nDo you want to pay ${feeToPay} Excoins to get a 4-hour access pass?`;
      
    const confirmPay = window.confirm(confirmMessage);
    if (!confirmPay) return;
    
    if (excoinBalance < feeToPay) {
      showNotification(`Insufficient Excoins. You need ${feeToPay} EX. Your balance: ${excoinBalance} EX.`, 'error');
      return;
    }
    
    isEnteringClassroomRef.current = true;
    setIsEnteringClassroom(true);
    
    try {
      const ownerUid = selectedSchool?.creatorUid;
      const walletRef = doc(db, 'wallets', user.uid);
      const historyRef = doc(collection(db, `wallets/${user.uid}/history`));

      const ownerWalletRef = ownerUid ? doc(db, 'wallets', ownerUid) : null;
      const ownerHistoryRef = ownerUid ? doc(collection(db, `wallets/${ownerUid}/history`)) : null;

      const txResult = await runTransaction(db, async (transaction) => {
        const walletDoc = await transaction.get(walletRef);
        if (!walletDoc.exists()) return { success: false, reason: 'uninitialized' };
        
        const data = walletDoc.data();
        const currentBalance = data.excoin_balance || 0;

        if (currentBalance < feeToPay) return { success: false, reason: 'insufficient' };

        // 1. Debit feeToPay from entering user
        transaction.update(walletRef, {
          excoin_balance: currentBalance - feeToPay,
          last_transaction: serverTimestamp()
        });

        transaction.set(historyRef, {
          amount: feeToPay,
          type: 'debit',
          currency: 'excoins',
          description: `${kindTitle} Entry Access: ${c.name} (${burnShare} EX Burned, ${ownerShare} EX to Owner)`,
          timestamp: serverTimestamp()
        });

        // 2. Credit ownerShare to institution owner if different and exists
        if (ownerWalletRef && ownerHistoryRef && ownerUid && ownerUid !== user.uid) {
          const ownerWalletDoc = await transaction.get(ownerWalletRef);
          if (!ownerWalletDoc.exists()) {
            transaction.set(ownerWalletRef, {
              userId: ownerUid,
              balance: 0,
              excoin_balance: ownerShare,
              tier: 'Standard',
              last_transaction: serverTimestamp()
            });
          } else {
            const ownerBalance = ownerWalletDoc.data().excoin_balance || 0;
            transaction.update(ownerWalletRef, {
              excoin_balance: ownerBalance + ownerShare,
              last_transaction: serverTimestamp()
            });
          }

          transaction.set(ownerHistoryRef, {
            amount: ownerShare,
            type: 'credit',
            currency: 'excoins',
            description: `Earned ${ownerShare} EX from Classroom/Hub Entry Admission (${c.name}) by ${userDoc?.displayName || user.email || 'Member'}`,
            timestamp: serverTimestamp()
          });
        }

        return { success: true };
      });

      if (txResult.success) {
        try {
          const updatedSessions = {
            ...paidSessions,
            [user.uid]: now
          };
          const paidUsers = c.paidUsers || [];
          const updatedPaidUsers = paidUsers.includes(user.uid) ? paidUsers : [...paidUsers, user.uid];
          
          await updateDoc(doc(db, 'classrooms', c.id), {
            paidUsers: updatedPaidUsers,
            paidSessions: updatedSessions
          });
          
          showNotification('10 Excoins processed: 5 EX credited to institution owner, 5 EX permanently burned!', 'success');
          setSelectedClassroom({
            ...c,
            paidUsers: updatedPaidUsers,
            paidSessions: updatedSessions
          });
          setClassroomActiveTab('stream');
        } catch (err) {
          console.error('Error updating classroom paid status:', err);
          // Still allow them to enter since we successfully debited their wallet
          const updatedSessions = {
            ...paidSessions,
            [user.uid]: now
          };
          const paidUsers = c.paidUsers || [];
          const updatedPaidUsers = paidUsers.includes(user.uid) ? paidUsers : [...paidUsers, user.uid];
          setSelectedClassroom({
            ...c,
            paidUsers: updatedPaidUsers,
            paidSessions: updatedSessions
          });
          setClassroomActiveTab('stream');
        }
      } else {
        showNotification(
          txResult.reason === 'insufficient' ? 'Insufficient coins in your wallet!' : 'Error processing Excoin payment. Please try again.',
          'error'
        );
      }
    } finally {
      isEnteringClassroomRef.current = false;
      setIsEnteringClassroom(false);
    }
  };

  const handleConvertStarsToExcoin = async (stars: number) => {
    if (!user || stars < 10) return;
    const excoinsToReceive = Math.floor(stars / 10);
    const starsToDeduct = excoinsToReceive * 10;
    
    try {
      const walletRef = doc(db, 'wallets', user.uid);
      const historyRef = doc(collection(db, `wallets/${user.uid}/history`));

      await runTransaction(db, async (transaction) => {
        const walletDoc = await transaction.get(walletRef);
        if (!walletDoc.exists()) throw new Error('Wallet not found');
        
        const data = walletDoc.data();
        const currentStars = data.balance || 0;
        const currentCoins = data.excoin_balance || 0;

        if (currentStars < starsToDeduct) throw new Error('Insufficient Stars');

        transaction.update(walletRef, {
          balance: currentStars - starsToDeduct,
          excoin_balance: currentCoins + excoinsToReceive,
          last_transaction: serverTimestamp()
        });

        transaction.set(historyRef, {
          amount: starsToDeduct,
          type: 'debit',
          currency: 'stars',
          description: `Converted ${starsToDeduct} Stars to ${excoinsToReceive} Excoin(s)`,
          timestamp: serverTimestamp()
        });

        const historyRef2 = doc(collection(db, `wallets/${user.uid}/history`));
        transaction.set(historyRef2, {
          amount: excoinsToReceive,
          type: 'credit',
          currency: 'excoins',
          description: `Received from Star conversion`,
          timestamp: serverTimestamp()
        });
      });
      showNotification(`Successfully converted to ${excoinsToReceive} Excoin(s)`, 'success');
      return true;
    } catch (err) {
      handleFirestoreError(err, OperationType.WRITE, `wallets/${user.uid}`);
      return false;
    }
  };

